import logging
from typing import Set, List, Optional, Iterable, Any, Dict, Mapping

import numpy as np
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from scipy.interpolate import NearestNDInterpolator

logger = logging.getLogger(__name__)


def _parse_heights(obj: Any) -> Dict[str, float]:
    try:
        return {str(class_name): float(height) for class_name, height in obj.items()}
    except (ValueError, AttributeError) as exception:
        raise ValueError(
            f"Unsupported value for 'heights', "
            f"expected 'dict[str, float]', found '{obj}'"
        ) from exception


class SliceClassifier(Classifier):
    """This classifier extract and classifies horizontal slices in a point cloud.
    Extracts a DTM from the points classifies as ``ground`` and computes slices
    based on the heights provided by the user. Slices are non-overlapping.

    Heights are relative to the ground. They must be strictly positive numbers.
    """

    def __init__(
        self,
        heights: Optional[Dict[str, float]] = None,
        stage_name: Optional[str] = None,
    ) -> None:
        super().__init__(stage_name)
        self.heights = heights or {}

    @property
    def heights(self) -> Mapping[str, float]:
        return self._heights

    @heights.setter
    def heights(self, heights: Mapping[str, float]) -> None:
        if any(height <= 0.0 for height in heights.values()):
            raise ValueError(f"The heights must be strictly positive. Found {heights}")
        self._heights = heights

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "heights",
                "A dictionary that maps slice class names to their upper "
                "bound (in meters). Heights must be strictly positive numbers. "
                "The slice class names must be defined in the classification codes "
                "of the pipeline.",
                type_cast=_parse_heights,
                required=True,
            )
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        ground_id = pipeline_metadata.classification_codes["ground"]
        ground_mask = cloud.classification == ground_id
        ground_coords = cloud.coords[ground_mask]
        if len(ground_coords) == 0:
            return (cloud,)
        dtm = NearestNDInterpolator(ground_coords[:, :2], ground_coords[:, 2])
        non_ground_coords = cloud.coords[~ground_mask]
        projected_z = dtm(non_ground_coords[:, :2])
        heights = non_ground_coords[:, 2] - projected_z
        non_ground_indices = np.flatnonzero(~ground_mask)
        min_slice_height: float = 0.0
        for slice_name, max_slice_height in sorted(
            self.heights.items(), key=lambda item: item[1]
        ):
            slice_id = pipeline_metadata.classification_codes[slice_name]
            cloud.classification[
                non_ground_indices[
                    (heights >= min_slice_height) & (heights < max_slice_height)
                ]
            ] = slice_id
            min_slice_height = max_slice_height
        return (cloud,)

    def input_classes(self) -> Set[str]:
        return {"ground"}

    def output_classes(self) -> Set[str]:
        return set(self.heights)
